import React from 'react';
import { Package, Truck, ShoppingBag, CheckCircle } from 'lucide-react';
import '../../assets/styles/OrderTracker.css';

const milestones = [
  { id: 'Order Placed', label: 'Placed', icon: ShoppingBag },
  { id: 'In Transit', label: 'Transit', icon: Truck },
  { id: 'Out for Delivery', label: 'Out', icon: Package },
  { id: 'Delivered', label: 'Delivered', icon: CheckCircle },
];

const OrderTracker = ({ status }) => {
  const currentStep = milestones.findIndex(m => m.id === status);
  const progressPercentage = (currentStep / (milestones.length - 1)) * 100;

  return (
    <div className="order-tracker-container">
      <div className="tracker-line-bg">
        <div 
          className="tracker-line-progress" 
          style={{ width: `${progressPercentage}%` }}
        />

        {/* The Running Truck */}
        <div 
          className="running-truck" 
          style={{ left: `${progressPercentage}%` }}
        >
          <div className="truck-body">
            <Truck size={20} color="var(--accent-gold)" fill="var(--accent-gold)" fillOpacity={0.2} />
          </div>
          <div className="truck-wheels">
            <div className="wheel"></div>
            <div className="wheel"></div>
          </div>
        </div>
      </div>

      <div className="milestones-row">
        {milestones.map((milestone, index) => {
          const Icon = milestone.icon;
          const isActive = index <= currentStep;
          const isCurrent = index === currentStep;

          return (
            <div 
              key={milestone.id} 
              className={`milestone-item ${isActive ? 'active' : ''} ${isCurrent ? 'current' : ''}`}
            >
              <div className="milestone-icon-wrapper">
                <Icon size={16} />
              </div>
              <span className="milestone-label">{milestone.label}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default OrderTracker;
